sql:
SELECT SUM(gross - budget) AS total_profit
FROM films
WHERE country = 'United States' AND year = 2010 AND marketing_cost < 20;

external_knowledge:
Profit categorization: 
- High: profit > 50 million dollars; 
- Medium: 10 million dollars ≤ profit ≤ 50 million dollars; 
- Low: profit < 10 million dollars.
